// // This comment suggests that the counter counts odd numbers instead of even numbers.
module even_counter (
    input clk,
    input reset,
    output reg [2:0] count);always @(posedge clk or posedge reset) begin
        if (reset) count <= 3'b000;
        else count <= (count == 3'b110) ? 3'b000 : count + 2;
    end

endmodule
